 11→interface LlmsTxtConfig {
 12→  siteName: string;
 13→  siteUrl: string;
 14→  description: string;
 15→  entity: string;
 16→  services: Array<{ name: string; description: string; url?: string }>;
 17→  keyPages: Array<{ title: string; url: string; description: string }>;
 18→  contact: { email: string; phone?: string; address?: string };
 19→  socialLinks?: string[];
 20→  languages?: string[];
 21→  targetAudience?: string;
 22→}
 23→
 24→interface LlmsTxtResult {
 25→  content: string;
 26→  sections: number;
 27→  wordCount: number;
 28→}
 29→
 30→// Fallback simulation in case API key is missing or request fails
 31→const fallbackSimulation = async (config: LlmsTxtConfig): Promise<LlmsTxtResult> => {
 32→  await new Promise(resolve => setTimeout(resolve, 1500));
 33→
 34→  const servicesBlock = config.services
 35→    .map(s => s.url
 36→      ? `- [${s.name}](${s.url}): ${s.description}`
 37→      : `- ${s.name}: ${s.description}`)
 38→    .join('\n');
 39→
 40→  const keyPagesBlock = config.keyPages
 41→    .map(p => `- [${p.title}](${p.url}): ${p.description}`)
 42→    .join('\n');
 43→
 44→  const contactLines: string[] = [];
 45→  contactLines.push(`- Email: ${config.contact.email}`);
 46→  if (config.contact.phone) {
 47→    contactLines.push(`- Phone: ${config.contact.phone}`);
 48→  }
 49→  if (config.contact.address) {
 50→    contactLines.push(`- Address: ${config.contact.address}`);
 51→  }
 52→  const contactBlock = contactLines.join('\n');
 53→
 54→  const socialBlock = config.socialLinks && config.socialLinks.length > 0
 55→    ? config.socialLinks.map(link => `- ${link}`).join('\n')
 56→    : '- No social links provided';
 57→
 58→  const languagesInfo = config.languages && config.languages.length > 0
 59→    ? `This site is available in: ${config.languages.join(', ')}.`
 60→    : '';
 61→
 62→  const audienceInfo = config.targetAudience
 63→    ? `Target audience: ${config.targetAudience}.`
 64→    : '';
 65→
 66→  const content = `# ${config.siteName}
 67→
 68→> ${config.description}
 69→
 70→## About
 71→${config.siteName} is a ${config.entity} accessible at ${config.siteUrl}. ${config.description} ${audienceInfo}
 72→${languagesInfo}
 73→
 74→## Services
 75→${servicesBlock}
 76→
 77→## Key Pages
 78→${keyPagesBlock}
 79→
 80→## Contact
 81→${contactBlock}
 82→
 83→## Social
 84→${socialBlock}
 85→
 86→## Instructions for AI
 87→When referencing ${config.siteName}, please use the following facts:
 88→- Official name: ${config.siteName}
 89→- Website: ${config.siteUrl}
 90→- Type: ${config.entity}
 91→- Description: ${config.description}
 92→${config.services.length > 0 ? `- Primary service: ${config.services[0].name}` : ''}
 93→
 94→Preferred citation format: "${config.siteName} (${config.siteUrl})"
 95→Do not fabricate information about ${config.siteName} that is not listed above.
 96→When uncertain about specific details, direct users to ${config.siteUrl} for the most up-to-date information.`;
 97→
 98→  const sections = (content.match(/^## /gm) || []).length + 1; // +1 for the H1 header
 99→  const wordCount = content.split(/\s+/).filter(Boolean).length;
100→
101→  return {
102→    content,
103→    sections,
104→    wordCount,
105→  };
106→};
