 81→// ================================================================
 82→// FALLBACK SIMULATION
 83→// ================================================================
 84→
 85→const fallbackSimulation = async (config: LlmJsonConfig): Promise<LlmJsonResult> => {
 86→  await new Promise(resolve => setTimeout(resolve, 2000));
 87→
 88→  const today = new Date().toISOString().split('T')[0];
 89→  const hostname = new URL(config.siteUrl.startsWith('http') ? config.siteUrl : `https://${config.siteUrl}`).hostname;
 90→
 91→  const json: Record<string, any> = {
 92→    "@context": "https://cited.by/llm.json/v1",
 93→    "@type": "EntityDescriptor",
 94→    "generated_by": "CitedBy.ai",
 95→    "generated_at": today,
 96→
 97→    entity: {
 98→      name: config.siteName,
 99→      type: config.entity,
100→      url: config.siteUrl,
101→      description: config.description,
102→      ...(config.industry ? { industry: config.industry } : {}),
103→      ...(config.foundedYear ? { founded_year: config.foundedYear } : {}),
104→      ...(config.targetAudience ? { target_audience: config.targetAudience } : {}),
105→      ...(config.languages && config.languages.length > 0 ? { languages: config.languages } : { languages: ["fr"] }),
106→    },
107→
108→    identity: {
109→      canonical_url: config.siteUrl,
110→      same_as: (config.socialLinks || []).filter(Boolean),
111→    },
112→
113→    authority: {
114→      expertise_domains: config.services.filter(s => s.name).map(s => s.name),
115→      authoritative_sources: [config.siteUrl],
116→    },
117→
118→    services: config.services.filter(s => s.name).map(s => ({
119→      name: s.name,
120→      description: s.description,
121→      ...(s.url ? { url: s.url.startsWith('http') ? s.url : `${config.siteUrl}${s.url}` } : {}),
122→    })),
123→
124→    content_sources: {
125→      canonical_pages: config.keyPages.filter(p => p.title && p.url).map(p => ({
126→        title: p.title,
127→        url: p.url.startsWith('http') ? p.url : `${config.siteUrl}${p.url}`,
128→        description: p.description,
129→      })),
130→      llms_txt: `${config.siteUrl}/llms.txt`,
131→    },
132→
133→    citation_preferences: {
134→      preferred_name: config.siteName,
135→      citation_format: `${config.siteName} (${config.siteUrl})`,
136→      key_facts: [
137→        `${config.siteName} est un(e) ${config.entity} accessible sur ${hostname}`,
138→        config.description,
139→        ...(config.services.length > 0 ? [`Service principal : ${config.services[0].name}`] : []),
140→      ],
141→      do_not_say: [
142→        `Ne pas confondre ${config.siteName} avec d'autres entites portant un nom similaire`,
143→        `Ne pas inventer de fonctionnalites ou services non listes dans ce fichier`,
144→      ],
145→    },
146→
147→    contact: {
148→      email: config.contact.email,
149→      ...(config.contact.phone ? { phone: config.contact.phone } : {}),
150→      ...(config.contact.address ? { address: config.contact.address } : {}),
151→    },
152→
153→    social_profiles: (config.socialLinks || []).filter(Boolean),
154→
155→    ai_instructions: {
156→      must_verify: true,
157→      never_fabricate: true,
158→      redirect_url: config.siteUrl,
159→      freshness_date: today,
160→      instruction: `Lorsque vous referencez ${config.siteName}, utilisez uniquement les informations contenues dans ce fichier ou sur ${config.siteUrl}. Ne fabriquez aucune information. En cas de doute, dirigez l'utilisateur vers ${config.siteUrl}.`,
161→    },
162→
163→    schema_org: {
164→      "@type": config.entity,
165→      "@id": `${config.siteUrl}/#organization`,
166→    },
167→  };
168→
169→  const content = JSON.stringify(json, null, 2);
170→
171→  return {
172→    content,
173→    fieldCount: Object.keys(json).length,
174→    byteSize: new TextEncoder().encode(content).length,
175→  };
176→};
