175→  }
176→
177→  const ai = new GoogleGenAI({ apiKey });
178→
179→  const engineResponseSchema: Schema = {
180→    type: Type.OBJECT,
181→    properties: {
182→      engine: {
183→        type: Type.STRING,
184→        enum: ['ChatGPT', 'Claude', 'Perplexity', 'Gemini', 'AI Overviews'],
185→        description: "The AI engine being simulated",
186→      },
187→      response: {
188→        type: Type.STRING,
189→        description: "The simulated AI response text (3-5 sentences). ChatGPT: conversational. Claude: analytical and structured. Perplexity: include source citation format [1][2]. Gemini: factual and data-driven.",
190→      },
191→      mentionType: {
192→        type: Type.STRING,
193→        enum: ['direct', 'indirect', 'comparison', 'absent'],
194→        description: "How the brand is mentioned: direct (by name in context), indirect (alluded to), comparison (mentioned alongside competitors), absent (not mentioned)",
195→      },
196→      mentionScore: {
197→        type: Type.NUMBER,
198→        description: "0-100 score of how prominently the brand is featured in the response",
199→      },
200→      sentiment: {
201→        type: Type.STRING,
202→        enum: ['positive', 'neutral', 'negative'],
203→        description: "Sentiment of the mention toward the brand",
204→      },
205→      citationPresent: {
206→        type: Type.BOOLEAN,
207→        description: "Whether the engine includes a source citation or link for the brand",
208→      },
209→      excerpt: {
210→        type: Type.STRING,
211→        description: "The specific part of the response that mentions the brand, or empty string if absent",
212→      },
213→    },
214→    required: ['engine', 'response', 'mentionType', 'mentionScore', 'sentiment', 'citationPresent', 'excerpt'],
215→  };
216→
217→  const resultSchema: Schema = {
218→    type: Type.OBJECT,
219→    properties: {
220→      overallScore: {
221→        type: Type.NUMBER,
222→        description: "0-100 average visibility score across all engines",
223→      },
224→      engines: {
225→        type: Type.ARRAY,
226→        items: engineResponseSchema,
227→        description: "Simulated responses from 5 AI engines: ChatGPT, Claude, Perplexity, Gemini, AI Overviews",
228→      },
229→      improvements: {
230→        type: Type.ARRAY,
231→        items: { type: Type.STRING },
232→        description: "4-6 actionable improvement suggestions to increase AI citation visibility",
233→      },
234→      competitorsMentioned: {
235→        type: Type.ARRAY,
236→        items: { type: Type.STRING },
237→        description: "Names of competitors mentioned across the simulated responses",
238→      },
239→    },
240→    required: ['overallScore', 'engines', 'improvements', 'competitorsMentioned'],
241→  };
242→
243→  const industryContext = industry ? `The brand operates in the "${industry}" industry.` : '';
244→
245→  const prompt = `
246→    CONTEXT:
247→    You are an expert in AI visibility and Answer Engine Optimization (AEO).
248→    A user wants to understand how different AI engines would respond to a query about their brand.
249→
250→    INPUTS:
251→    - User query: "${query}"
252→    - Brand name: "${brandName}"
253→    - Brand URL: ${brandUrl}
254→    ${industryContext}
255→
256→    MISSION:
257→    Simulate how each of the 5 major AI engines (ChatGPT, Claude, Perplexity, Gemini, AI Overviews) would realistically respond to the query "${query}".
258→
259→    RULES FOR EACH ENGINE:
260→    1. **ChatGPT**: Conversational, friendly tone. May mention the brand if it has strong web presence. Tends to recommend well-known solutions first.
261→    2. **Claude**: Analytical, structured analysis. Cautious about unverified claims. Will note if it lacks training data on the brand.
262→    3. **Perplexity**: Always includes numbered source citations [1][2][3]. Relies heavily on indexed web sources, comparison sites, and reviews.
263→    4. **Gemini**: Factual, data-driven. Focuses on market data, statistics, and objective comparisons.
264→    5. **AI Overviews**: Google's AI-generated SERP snippet. Short, factual answer-box format with bullet points and source links. Tends to cite sources directly and use comparison/list format.
265→
266→    IMPORTANT:
267→    - Be realistic: if the brand is not well-known, some engines should NOT mention it or mention it minimally.
268→    - Each response should be 3-5 sentences of natural AI-style text.
269→    - Vary the mentionType across engines (not all should be the same).
270→    - Include real competitor names relevant to the industry.
271→    - Provide 4-6 specific, actionable improvement suggestions.
272→    - The overallScore should reflect the average mentionScore across engines.
273→
274→    Respond strictly in the JSON schema provided.
275→  `;
276→
277→  const response = await ai.models.generateContent({
278→    model: 'gemini-2.5-flash',
279→    contents: prompt,
280→    config: {
281→      responseMimeType: 'application/json',
282→      responseSchema: resultSchema,
283→      temperature: 0.4,
284→    },
285→  });
286→
287→  let output = response.text;
288→  if (!output) {
289→    throw new Error("Empty response from AI");
290→  }
291→
292→  // Clean up potentially leaked markdown fences despite JSON mode
293→  output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
294→
295→  const jsonResponse = JSON.parse(output);
296→
297→  return {
298→    query,
299→    brandName,
