 20→// ── Deterministic helpers ──
 21→const seededRandom = (seed: number, offset: number): number => {
 22→  const raw = ((seed * 37 + offset * 19 + 11) * 17) % 1000;
 23→  return raw / 1000;
 24→};
 25→
 26→const seededInt = (seed: number, offset: number, min: number, max: number): number => {
 27→  return min + Math.round(seededRandom(seed, offset) * (max - min));
 28→};
 29→
 30→const seededFloat = (seed: number, offset: number, min: number, max: number): number => {
 31→  return Math.round((min + seededRandom(seed, offset) * (max - min)) * 10) / 10;
 32→};
