 81→    const engineSov = seededFloat(seed, 20 + i, 5, 45);
 82→    const engineSentiment: SentimentBreakdown = {
 83→      positive: seededInt(seed, 30 + i, 30, 70),
 84→      neutral: seededInt(seed, 40 + i, 15, 40),
 85→      negative: 0,
 86→    };
 87→    engineSentiment.negative = Math.max(0, 100 - engineSentiment.positive - engineSentiment.neutral);
 88→    if (engineSentiment.negative < 0) {
 89→      engineSentiment.neutral += engineSentiment.negative;
 90→      engineSentiment.negative = 0;
 91→    }
 92→
 93→    const topQueries = queryPool
 94→      .sort(() => seededRandom(seed, 50 + i * 10) - 0.5)
 95→      .slice(0, seededInt(seed, 60 + i, 3, 5));
 96→
 97→    return {
 98→      engine,
 99→      totalCitations: engineCitations,
100→      shareOfVoice: engineSov,
101→      avgPosition: seededFloat(seed, 70 + i, 1, 5),
