222→export const runMonitoringScan = async (
223→  brandName: string,
224→  url: string,
225→  period: '7d' | '30d' | '90d' = '30d'
226→): Promise<MonitoringResult> => {
227→  const apiKey = getApiKey();
228→  if (!apiKey) {
229→    console.warn("API_KEY not found, using simulation.");
230→    return fallbackSimulation(brandName, url, period);
231→  }
232→
233→  try {
234→    const ai = new GoogleGenAI({ apiKey });
235→
236→    const prompt = `Tu es un expert en monitoring de visibilite de marque sur les moteurs de reponse IA (ChatGPT, Claude, Perplexity, Gemini, AI Overviews).
237→
238→Analyse la marque "${brandName}" (${url}) et genere un rapport de monitoring IA complet pour les ${period === '7d' ? '7 derniers jours' : period === '30d' ? '30 derniers jours' : '90 derniers jours'}.
239→
240→Genere un JSON avec:
241→- totalCitations: nombre total de citations detectees
242→- shareOfVoice: pourcentage de part de voix (0-100)
243→- overallSentiment: { positive: number, neutral: number, negative: number } (somme = 100)
244→- trend: evolution en % vs periode precedente
245→- engineResults: tableau de 5 objets (ChatGPT, Claude, Perplexity, Gemini, AI Overviews) avec totalCitations, shareOfVoice, avgPosition, sentiment, trend, topQueries
246→- citations: tableau de 15-20 citations recentes avec engine, query, position, date, sentiment, snippet, confidence
247→- competitors: tableau de 4 concurrents avec name, totalCitations, shareOfVoice, avgSentiment, trend, dominantEngine
248→- timeSeries: tableau de points jour par jour avec date, citations, chatgpt, claude, perplexity, gemini, aiOverviews
