 34→    "name": profile.name,
 35→    "jobTitle": profile.jobTitle,
 36→    "worksFor": { "@type": "Organization", "name": profile.organization },
 37→    "description": bioShort,
 38→    ...(profile.photoUrl && { "image": profile.photoUrl }),
 39→    "sameAs": profile.socialProfiles.map(s => s.url),
 40→    ...(profile.credentials.length > 0 && {
 41→      "hasCredential": profile.credentials.map(c => ({
 42→        "@type": "EducationalOccupationalCredential",
 43→        "name": c.name,
 44→        "credentialCategory": c.type,
 45→        "recognizedBy": { "@type": "Organization", "name": c.issuer }
 46→      }))
 47→    }),
 48→    ...(profile.education.length > 0 && {
 49→      "alumniOf": profile.education.map(e => ({
 50→        "@type": "EducationalOrganization",
 51→        "name": e.institution
 52→      }))
 53→    }),
 54→    ...(profile.awards && profile.awards.length > 0 && {
 55→      "award": profile.awards.map(a => a.name)
 56→    }),
 57→    "knowsAbout": profile.specializations,
 58→  }, null, 2);
 59→
 60→  const htmlBlock = `<div class="flex items-start gap-4 p-6 bg-[#111111] border border-white/[0.06] rounded-2xl">
 61→  ${profile.photoUrl ? `<img src="${profile.photoUrl}" alt="${profile.name}" class="w-16 h-16 rounded-full object-cover border-2 border-purple-500/30" />` : `<div class="w-16 h-16 rounded-full bg-purple-500/20 flex items-center justify-center text-purple-400 font-bold text-xl">${profile.name.charAt(0)}</div>`}
 62→  <div class="flex-1">
 63→    <h3 class="text-lg font-bold text-white">${profile.name}</h3>
 64→    <p class="text-sm text-purple-400 font-medium">${profile.jobTitle} — ${profile.organization}</p>
 65→    <p class="text-sm text-gray-400 mt-2 leading-relaxed">${bioShort}</p>
 66→    <div class="flex items-center gap-3 mt-3">
 67→      ${profile.socialProfiles.map(s => `<a href="${s.url}" target="_blank" rel="noopener" class="text-xs text-gray-500 hover:text-purple-400 transition-colors">${s.platform}</a>`).join('\n      ')}
 68→    </div>
 69→  </div>
 70→</div>`;
 71→
 72→  return { bioShort, bioLong, schemaOrg, htmlBlock };
 73→};
